import type { AppTheme } from "@t3tools/contracts";
import { useColorTheme } from "../theme/ThemeProvider";

interface ThemeSwatchProps {
  theme: AppTheme;
  selected: boolean;
  onSelect: () => void;
}

function ThemeSwatch({ theme, selected, onSelect }: ThemeSwatchProps) {
  const { colors } = theme;
  return (
    <button
      type="button"
      role="radio"
      aria-checked={selected}
      aria-label={theme.label}
      onClick={onSelect}
      className={[
        "group relative flex flex-col overflow-hidden rounded-xl border-2 transition-all",
        "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2",
        selected
          ? "border-primary shadow-md shadow-primary/10"
          : "border-border hover:border-primary/40",
      ].join(" ")}
    >
      {/* Mini app preview */}
      <div
        className="flex h-14 w-full overflow-hidden"
        style={{ background: colors.background }}
        aria-hidden="true"
      >
        {/* Sidebar strip */}
        <div
          className="flex w-9 flex-col gap-1 px-1.5 pt-2"
          style={{ background: colors.sidebar }}
        >
          {([0.65, 0.45, 0.55] as const).map((opacity, i) => (
            <div
              // biome-ignore lint/suspicious/noArrayIndexKey: static preview
              key={i}
              className="rounded-full"
              style={{
                background: colors.foreground,
                opacity,
                height: "3px",
                width: `${55 + i * 12}%`,
              }}
            />
          ))}
        </div>

        {/* Editor area */}
        <div className="flex flex-1 flex-col gap-1 px-1.5 pt-2" style={{ background: colors.editor }}>
          {([0.55, 0.35, 0.45, 0.25] as const).map((opacity, i) => (
            <div
              // biome-ignore lint/suspicious/noArrayIndexKey: static preview
              key={i}
              className="rounded-full"
              style={{
                background: i === 1 ? colors.accent : colors.foreground,
                opacity,
                height: "2px",
                width: `${38 + i * 14}%`,
              }}
            />
          ))}
        </div>
      </div>

      {/* Status bar */}
      <div
        className="flex h-2.5 shrink-0 items-center px-1.5"
        style={{ background: colors.statusBar }}
        aria-hidden="true"
      >
        <div
          className="rounded-full"
          style={{ background: colors.accent, opacity: 0.75, height: "3px", width: "18px" }}
        />
      </div>

      {/* Label row */}
      <div
        className="flex items-center justify-between px-2.5 py-2"
        style={{
          background: colors.background,
          borderTop: `1px solid ${colors.foreground}18`,
        }}
      >
        <span className="text-[11px] font-medium" style={{ color: colors.foreground }}>
          {theme.label}
        </span>
        {selected && (
          <span
            className="rounded px-1 py-0.5 text-[9px] font-semibold uppercase tracking-wide"
            style={{ background: `${colors.accent}22`, color: colors.accent }}
          >
            Active
          </span>
        )}
      </div>
    </button>
  );
}

/**
 * A visual theme picker that renders a swatch preview for each built-in theme.
 * Drop this into any settings surface that manages color-theme selection.
 */
export function ThemeSelector() {
  const { currentTheme, setTheme, themes } = useColorTheme();
  return (
    <div role="radiogroup" aria-label="Color theme" className="grid grid-cols-3 gap-3">
      {themes.map((theme) => (
        <ThemeSwatch
          key={theme.id}
          theme={theme}
          selected={currentTheme.id === theme.id}
          onSelect={() => setTheme(theme.id)}
        />
      ))}
    </div>
  );
}

