/* ============================================================
   Named color themes вЂ“ applied via data-color-theme attribute.
   Placed after the default :root rules so attribute-selector
   specificity ([0,1,1]) wins on a later position in the cascade.
   ============================================================ */

/* T3 Dark вЂ” Catppuccin Mocha-inspired with violet accents */
:root[data-color-theme="t3-dark"] {
  color-scheme: dark;
  --background: #1e1e2e;
  --foreground: #cdd6f4;
  --card: #181825;
  --card-foreground: #cdd6f4;
  --popover: #1e1e2e;
  --popover-foreground: #cdd6f4;
  --primary: #7c3aed;
  --primary-foreground: #ffffff;
  --secondary: rgba(255, 255, 255, 0.06);
  --secondary-foreground: #cdd6f4;
  --muted: rgba(255, 255, 255, 0.06);
  --muted-foreground: #a6adc8;
  --accent: rgba(255, 255, 255, 0.06);
  --accent-foreground: #cdd6f4;
  --destructive: #f38ba8;
  --destructive-foreground: #ff8fab;
  --border: rgba(255, 255, 255, 0.1);
  --input: rgba(255, 255, 255, 0.12);
  --ring: #7c3aed;
  --info: #89b4fa;
  --info-foreground: #89dceb;
  --success: #a6e3a1;
  --success-foreground: #94e2d5;
  --warning: #f9e2af;
  --warning-foreground: #fab387;
  /* Extended theme surface tokens */
  --theme-sidebar-bg: #181825;
  --theme-editor-bg: #1e1e2e;
  --theme-terminal-bg: #11111b;
  --theme-status-bar-bg: #181825;
  --theme-status-bar-fg: #a6adc8;
}

/* T3 Light вЂ” Clean light theme with violet accents */
:root[data-color-theme="t3-light"] {
  color-scheme: light;
  --background: #ffffff;
  --foreground: #1e1e2e;
  --card: #f8f8fc;
  --card-foreground: #1e1e2e;
  --popover: #ffffff;
  --popover-foreground: #1e1e2e;
  --primary: #6d28d9;
  --primary-foreground: #ffffff;
  --secondary: rgba(0, 0, 0, 0.05);
  --secondary-foreground: #1e1e2e;
  --muted: rgba(0, 0, 0, 0.05);
  --muted-foreground: #6b7280;
  --accent: rgba(0, 0, 0, 0.05);
  --accent-foreground: #1e1e2e;
  --destructive: #ef4444;
  --destructive-foreground: #b91c1c;
  --border: rgba(0, 0, 0, 0.1);
  --input: rgba(0, 0, 0, 0.12);
  --ring: #6d28d9;
  --info: #3b82f6;
  --info-foreground: #1d4ed8;
  --success: #10b981;
  --success-foreground: #047857;
  --warning: #f59e0b;
  --warning-foreground: #b45309;
  /* Extended theme surface tokens */
  --theme-sidebar-bg: #f4f4f8;
  --theme-editor-bg: #ffffff;
  --theme-terminal-bg: #1e1e2e;
  --theme-status-bar-bg: #ede9fe;
  --theme-status-bar-fg: #6d28d9;
}

/* T3 Midnight вЂ” Tokyo Night-inspired deep blue palette */
:root[data-color-theme="t3-midnight"] {
  color-scheme: dark;
  --background: #1a1b26;
  --foreground: #a9b1d6;
  --card: #16161e;
  --card-foreground: #a9b1d6;
  --popover: #1a1b26;
  --popover-foreground: #a9b1d6;
  --primary: #7aa2f7;
  --primary-foreground: #1a1b26;
  --secondary: rgba(255, 255, 255, 0.06);
  --secondary-foreground: #a9b1d6;
  --muted: rgba(255, 255, 255, 0.06);
  --muted-foreground: #565f89;
  --accent: rgba(255, 255, 255, 0.06);
  --accent-foreground: #a9b1d6;
  --destructive: #f7768e;
  --destructive-foreground: #ff9e64;
  --border: rgba(255, 255, 255, 0.08);
  --input: rgba(255, 255, 255, 0.1);
  --ring: #7aa2f7;
  --info: #7aa2f7;
  --info-foreground: #7dcfff;
  --success: #9ece6a;
  --success-foreground: #73daca;
  --warning: #e0af68;
  --warning-foreground: #ff9e64;
  /* Extended theme surface tokens */
  --theme-sidebar-bg: #16161e;
  --theme-editor-bg: #1a1b26;
  --theme-terminal-bg: #0f0f17;
  --theme-status-bar-bg: #16161e;
  --theme-status-bar-fg: #565f89;
