import {
  createContext,
  useCallback,
  useContext,
  useEffect,
  useState,
  type ReactNode,
} from "react";
import type { AppTheme, ThemeId } from "@t3tools/contracts";
import { BUILT_IN_THEMES, DEFAULT_THEME_ID } from "./builtInThemes";

const STORAGE_KEY = "t3code:color-theme:v1";

export interface ColorThemeContextValue {
  currentTheme: AppTheme;
  setTheme: (id: ThemeId) => void;
  themes: ReadonlyArray<AppTheme>;
}

function readStoredThemeId(): ThemeId {
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    if (raw === "t3-dark" || raw === "t3-light" || raw === "t3-midnight") return raw;
  } catch {
    // localStorage unavailable (e.g. SSR)
  }
  return DEFAULT_THEME_ID;
}

function findTheme(id: ThemeId): AppTheme {
  return BUILT_IN_THEMES.find((t) => t.id === id) ?? (BUILT_IN_THEMES[0] as AppTheme);
}

function applyColorTheme(theme: AppTheme, suppressTransitions = false): void {
  if (typeof document === "undefined") return;
  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }
  document.documentElement.setAttribute("data-color-theme", theme.id);
  document.documentElement.classList.toggle("dark", theme.isDark);
  if (suppressTransitions) {
    // Force a reflow so no-transitions takes effect before class removal
    // oxlint-disable-next-line no-unused-expressions
    document.documentElement.offsetHeight;
    requestAnimationFrame(() => {
      document.documentElement.classList.remove("no-transitions");
    });
  }
}

// Apply immediately on module load to prevent flash before React mounts
applyColorTheme(findTheme(readStoredThemeId()));

const ColorThemeContext = createContext<ColorThemeContextValue | null>(null);

export function ThemeProvider({ children }: { children: ReactNode }) {
  const [themeId, setThemeIdState] = useState<ThemeId>(readStoredThemeId);
  const currentTheme = findTheme(themeId);

  const setTheme = useCallback((id: ThemeId) => {
    const theme = findTheme(id);
    localStorage.setItem(STORAGE_KEY, id);
    applyColorTheme(theme, true);
    setThemeIdState(id);
  }, []);

  // Sync theme changes made in other browser tabs
  useEffect(() => {
    const handleStorage = (e: StorageEvent) => {
      if (e.key !== STORAGE_KEY) return;
      const newId = readStoredThemeId();
      applyColorTheme(findTheme(newId), true);
      setThemeIdState(newId);
    };
    window.addEventListener("storage", handleStorage);
    return () => window.removeEventListener("storage", handleStorage);
  }, []);

  // Keep DOM in sync whenever the resolved theme changes
  useEffect(() => {
    applyColorTheme(currentTheme);
  }, [currentTheme]);

  return (
    <ColorThemeContext.Provider value={{ currentTheme, setTheme, themes: BUILT_IN_THEMES }}>
      {children}
    </ColorThemeContext.Provider>
  );
}

export function useColorTheme(): ColorThemeContextValue {
  const ctx = useContext(ColorThemeContext);
  if (!ctx) throw new Error("useColorTheme must be called within <ThemeProvider>");
  return ctx;
}

