tool_use_result.originalFile:
import { Schema } from "effect";

/** Identifiers for the built-in application color themes. */
export const ThemeId = Schema.Literal("t3-dark", "t3-light", "t3-midnight");
export type ThemeId = typeof ThemeId.Type;

/**
 * Color tokens every application theme must provide.
 * Each token maps to a CSS custom property applied to the document root.
 */
export interface ThemeColorTokens {
  /** Main page and panel background color */
  background: string;
  /** Primary text / foreground color */
  foreground: string;
  /** Brand accent color used for interactive elements */
  accent: string;
  /** Sidebar navigation panel background */
  sidebar: string;
  /** Editor content area background */
  editor: string;
  /** Integrated terminal pane background */
  terminal: string;
  /** Status bar background */
  statusBar: string;
}

/**
 * A fully-resolved application color theme.
 */
export interface AppTheme {
  /** Stable identifier вЂ“ used for storage and CSS attribute selection */
  id: ThemeId;
  /** Human-readable display label */
  label: string;
  /** Whether this theme renders as a dark-mode palette */
  isDark: boolean;
  /** Complete set of color tokens for this theme */
  colors: ThemeColorTokens;
}
